import React, { useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useNavigate, Link } from 'react-router-dom';
import { useFormik } from 'formik';
import { toast } from 'react-toastify';
import { loginCustomer, loginAdmin } from '../store/slices/authSlice';
import { loginSchema } from '../schemas';

export default function Login() {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { loading } = useSelector(s => s.auth);
  const [isAdmin, setIsAdmin] = useState(false);

  const formik = useFormik({
    initialValues: { email: '', password: '' },
    validationSchema: loginSchema,
    onSubmit: async (values) => {
      const action = isAdmin ? loginAdmin(values) : loginCustomer(values);
      const result = await dispatch(action);
      if (result.meta.requestStatus === 'fulfilled') {
        toast.success('Login successful!');
        navigate(isAdmin ? '/admin/dashboard' : '/dashboard');
      } else {
        toast.error(result.payload);
      }
    }
  });

  const err = { color: '#ef4444', fontSize: 12, marginTop: 4 };

  return (
    <div className="min-vh-100 d-flex align-items-center justify-content-center" style={{ background: '#f1f5f9', padding: '16px' }}>
      <div className="w-100" style={{ maxWidth: 420 }}>
        <div className="bg-white rounded-3 shadow p-4 p-md-5">
          <h2 className="mb-1" style={{ color: '#1e293b' }}>🏦 MyFin Bank</h2>
          <p className="text-secondary mb-4">Sign in to your account</p>

          <div className="d-flex gap-2 mb-4">
            {['Customer', 'Admin'].map(role => (
              <button
                key={role}
                type="button"
                onClick={() => setIsAdmin(role === 'Admin')}
                className="btn flex-fill"
                style={{
                  border: '1px solid #e2e8f0',
                  background: (isAdmin ? role === 'Admin' : role === 'Customer') ? '#3b82f6' : '#fff',
                  color: (isAdmin ? role === 'Admin' : role === 'Customer') ? '#fff' : '#64748b',
                  fontWeight: 600
                }}
              >
                {role}
              </button>
            ))}
          </div>

          <form onSubmit={formik.handleSubmit}>
            <div className="mb-3">
              <label className="form-label fw-semibold" style={{ fontSize: 13, color: '#374151' }}>Email</label>
              <input
                name="email" type="email"
                className="form-control"
                {...formik.getFieldProps('email')}
                placeholder="you@example.com"
              />
              {formik.touched.email && formik.errors.email && <div style={err}>{formik.errors.email}</div>}
            </div>
            <div className="mb-4">
              <label className="form-label fw-semibold" style={{ fontSize: 13, color: '#374151' }}>Password</label>
              <input
                name="password" type="password"
                className="form-control"
                {...formik.getFieldProps('password')}
                placeholder="••••••••"
              />
              {formik.touched.password && formik.errors.password && <div style={err}>{formik.errors.password}</div>}
            </div>
            <button
              type="submit" disabled={loading}
              className="btn w-100"
              style={{ background: '#3b82f6', color: '#fff', fontWeight: 700, fontSize: 15, padding: '12px' }}
            >
              {loading ? 'Signing in...' : 'Sign In'}
            </button>
          </form>

          <div className="text-center mt-3" style={{ fontSize: 13 }}>
            <Link to="/forgot-password" style={{ color: '#3b82f6' }}>Forgot Password?</Link>
            {' · '}
            <Link to="/register" style={{ color: '#3b82f6' }}>Create Account</Link>
          </div>
        </div>
      </div>
    </div>
  );
}
